    String line;
    while ((line = br.readLine()) != null) {
        String[] parts = line.split("\\s+");
        String level    = parts[2];   // INFO, ERROR, WARN
        String endpoint = parts[4];   // /api/...

        levelCounts.merge(level, 1L, Long::sum);
        if ("ERROR".equals(level)) {
            errorEndpoints.merge(endpoint, 1L, Long::sum);
        }
    }
