worked_example.final_code:
import java.io.*;
import java.nio.file.*;
import java.time.*;
import java.util.*;
import java.util.stream.*;

public class LogAnalyser {
    public static void main(String[] args) throws IOException {
        Path logFile = Path.of("server.log");
        Files.writeString(logFile,
            "2024-03-01 10:00:01 INFO  GET /api/orders 200 45ms\n" +
            "2024-03-01 10:00:02 ERROR GET /api/payment 500 1200ms\n" +
            "2024-03-01 10:00:03 WARN  GET /api/orders 429 12ms\n" +
            "2024-03-01 10:00:04 INFO  GET /api/users 200 30ms\n" +
            "2024-03-01 10:00:05 ERROR POST /api/payment 503 2000ms\n" +
            "2024-03-01 10:00:06 ERROR GET /api/products 500 800ms");

        Map<String, Long> levels    = new LinkedHashMap<>();
        Map<String, Long> errorEps  = new HashMap<>();
        int totalLines = 0;

        try (BufferedReader br = Files.newBufferedReader(logFile)) {
            String line;
            while ((line = br.readLine()) != null) {
                totalLines++;
                String[] p = line.split("\\s+");
                levels.merge(p[2], 1L, Long::sum);
                if ("ERROR".equals(p[2])) errorEps.merge(p[4], 1L, Long::sum);
            }
        }

        System.out.println("=== Log Analysis ===");
        levels.forEach((level, count) -> System.out.printf("  %-7s %d%n", level, count));
        System.out.println("--- Error endpoints ---");
        errorEps.entrySet().stream()
            .sorted((a, b) -> Long.compare(b.getValue(), a.getValue()))
            .forEach(e -> System.out.printf("  %-20s %d%n", e.getKey(), e.getValue()));
        System.out.println("Total lines: " + totalLines);

        // Write report:
        Path report = Path.of("report.txt");
        try (PrintWriter pw = new PrintWriter(
                new BufferedWriter(new FileWriter(report.toFile())))) {
            pw.println("Log Analysis Report");
            levels.forEach((lv, cnt) -> pw.printf("  %-7s %d%n", lv, cnt));
            pw.printf("%nError endpoints:%n");
            errorEps.entrySet().stream()
                .sorted((a,b) -> Long.compare(b.getValue(), a.getValue()))
                .forEach(e -> pw.printf("  %s: %d%n", e.getKey(), e.getValue()));
        }
        System.out.println("Report: " + Files.size(report) + " bytes");
    }
}

